import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { auth } from '../services/api';
import './Login.css';

export default function Login() {
  const [step, setStep] = useState('phone'); // 'phone' | 'otp'
  const [phone, setPhone] = useState('');
  const [otp, setOtp] = useState('');
  const [devOtp, setDevOtp] = useState(''); // shown in dev mode
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSendOtp = async () => {
    if (phone.length !== 10) return setError('Enter a valid 10-digit number');
    setError(''); setLoading(true);
    try {
      const res = await auth.requestOtp(phone);
      if (res.data.otp) setDevOtp(res.data.otp); // dev mode
      setStep('otp');
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to send OTP');
    } finally { setLoading(false); }
  };

  const handleVerifyOtp = async () => {
    if (otp.length !== 6) return setError('Enter the 6-digit OTP');
    setError(''); setLoading(true);
    try {
      const res = await auth.verifyOtp({ phone, otp });
      login(res.data.token, res.data.worker);
      navigate(res.data.isNew ? '/onboarding' : '/dashboard');
    } catch (err) {
      setError(err.response?.data?.error || 'Invalid OTP');
    } finally { setLoading(false); }
  };

  return (
    <div className="login-page">
      <div className="login-hero">
        <div className="hero-icon">🛡️</div>
        <h1>GigShield</h1>
        <p>Income protection for delivery partners</p>
      </div>

      <div className="login-card">
        {step === 'phone' ? (
          <>
            <h2>Get Started</h2>
            <p className="login-sub">Enter your mobile number to receive an OTP</p>
            <div className="input-group">
              <label>Mobile Number</label>
              <div className="phone-input-wrap">
                <span className="country-code">+91</span>
                <input
                  className="input phone-input"
                  type="tel"
                  maxLength={10}
                  placeholder="9876543210"
                  value={phone}
                  onChange={e => setPhone(e.target.value.replace(/\D/g, ''))}
                  onKeyDown={e => e.key === 'Enter' && handleSendOtp()}
                />
              </div>
            </div>
            {error && <div className="alert alert-error">{error}</div>}
            <button className="btn btn-primary" onClick={handleSendOtp} disabled={loading}>
              {loading ? 'Sending...' : 'Send OTP →'}
            </button>
          </>
        ) : (
          <>
            <button className="back-btn" onClick={() => setStep('phone')}>← Back</button>
            <h2>Verify OTP</h2>
            <p className="login-sub">Sent to +91 {phone}</p>
            {devOtp && (
              <div className="alert alert-info">
                <strong>Dev mode OTP:</strong> {devOtp}
              </div>
            )}
            <div className="input-group">
              <label>6-digit OTP</label>
              <input
                className="input otp-input"
                type="tel"
                maxLength={6}
                placeholder="• • • • • •"
                value={otp}
                onChange={e => setOtp(e.target.value.replace(/\D/g, ''))}
                onKeyDown={e => e.key === 'Enter' && handleVerifyOtp()}
              />
            </div>
            {error && <div className="alert alert-error">{error}</div>}
            <button className="btn btn-primary" onClick={handleVerifyOtp} disabled={loading}>
              {loading ? 'Verifying...' : 'Verify & Login →'}
            </button>
          </>
        )}
      </div>

      <p className="login-footer">
        For Zomato & Swiggy delivery partners 🍔
      </p>
    </div>
  );
}
